// sendJSONError helper to send error responses in JSON format.
func sendJSONError(ctx *fasthttp.RequestCtx, msg string, statusCode int) {
	ctx.SetStatusCode(statusCode)
	resp := PreviewResponse{Error: msg}
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using golang.org/x/net/html.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	for {
		tt := z.Next()

		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()

			// Check for <title>
			if t.Data == "title" {
				if z.Next() == html.TextToken {
					title = z.Token().Data
				}
			}

			// Check for <meta name="description" content="...">
			if t.Data == "meta" {
				var name, content string
				for _, attr := range t.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}

		// Optimization: If we found both, we could return early,
		// but sometimes descriptions are at the bottom or titles are duplicated.
		// For a robust preview, scanning the whole head/body is usually fast enough.
	}
}

