// parseHTMLPreview extracts title and meta description from HTML using x/net/html.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Optimization: if we found both, stop traversing (not easily possible with simple recursion without custom error, but good enough)
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
				// Title text is the first child of the title element
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			// Extract Meta Description
			if n.Data == "meta" && description == "" {
				var name, content string
				for _, a := range n.Attr {
					k := strings.ToLower(a.Key)
					if k == "name" {
						name = strings.ToLower(a.Val)
					}
					if k == "content" {
						content = a.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description, nil
}

