// isPrivateIP checks if an IP address belongs to private/reserved ranges.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// ssrfSafeDial is a custom dialer that resolves the hostname and checks if the IP is private.
// It prevents SSRF attacks by blocking connections to internal network addresses.
func ssrfSafeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var safeIP net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			safeIP = ip
			break
		}
	}

	if safeIP == nil {
		return nil, errors.New("security violation: access to private IP is blocked")
	}

	// Connect to the specific validated IP to prevent DNS rebinding
	remoteAddr := net.JoinHostPort(safeIP.String(), port)
	return net.DialTimeout("tcp", remoteAddr, 5*time.Second)
}

