// parseHTMLPreview extracts title and meta description from HTML using golang.org/x/net/html.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Optimization: stop traversing if both are found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract Title
