		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err != nil {
			panic(fmt.Errorf("parse error on %q: %v", cidr, err))
		}
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address belongs to a private or restricted network.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial is a custom dialer that resolves DNS and validates IPs to prevent SSRF.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		// If port is missing, try to assume standard ports based on context,
		// but fasthttp usually provides host:port.
		return nil, err
	}

	// Resolve IP
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	if len(ips) == 0 {
		return nil, fmt.Errorf("no IP addresses found for host: %s", host)
	}

	// Check the first resolved IP (or iterate all if you want failover, but security check all)
	targetIP := ips[0]
	if isPrivateIP(targetIP) {
		return nil, fmt.Errorf("access to private IP %s is forbidden", targetIP.String())
	}

	// Dial the validated IP directly to prevent DNS rebinding attacks
	// (Time-of-Check Time-of-Use)
	dialAddr := net.JoinHostPort(targetIP.String(), port)
	return net.DialTimeout("tcp", dialAddr, 5*time.Second)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and structure
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || parsedURL.Host == "" {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with security constraints
	client := &fasthttp.Client{
		// Use custom dialer for SSRF protection
		Dial: safeDial,
		// Prevent DoS by limiting response size (e.g., 1MB)
		MaxResponseBodySize: 1024 * 1024,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Follow redirects, but the custom Dial function will validate every new host
	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		// Differentiate between security blocks and network errors if needed
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Remote server returned status: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		// Log error internally, return generic error to user
		ctx.Error("Failed to parse content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
// Note: In a production environment, use "golang.org/x/net/html".
// This implementation uses basic byte scanning to avoid external dependencies
// for this specific task, while remaining safe from ReDoS.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Read full content (already limited by MaxResponseBodySize)
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	// Helper to find tag content case-insensitively
	// This is a simplified parser.
	lowerData := bytes.ToLower(data)

	// 1. Extract Title
	tStart := []byte("<title>")
	tEnd := []byte("</title>")

	startIdx := bytes.Index(lowerData, tStart)
	if startIdx != -1 {
		startIdx += len(tStart)
		endIdx := bytes.Index(lowerData[startIdx:], tEnd)
		if endIdx != -1 {
			title = string(bytes.TrimSpace(data[startIdx : startIdx+endIdx]))
		}
	}

	// 2. Extract Meta Description
	// Searching for <meta name="description" content="...">
	// We iterate over <meta tags to find the right one.
	metaStart := []byte("<meta")
	cursor := 0
	for {
		idx := bytes.Index(lowerData[cursor:], metaStart)
		if idx == -1 {
			break
		}
		cursor += idx + len(metaStart)

		// Find the end of this tag (>)
		endTag := bytes.IndexByte(lowerData[cursor:], '>')
		if endTag == -1 {
			break
		}

		tagContentLower := lowerData[cursor : cursor+endTag]
		tagContentOriginal := data[cursor : cursor+endTag]

		// Check if it has name="description"
		if bytes.Contains(tagContentLower, []byte(`name="description"`)) || 
		   bytes.Contains(tagContentLower, []byte(`name='description'`)) {

			// Extract content
			// Simple attribute parser
			cAttr := []byte("content=")
			cIdx := bytes.Index(tagContentLower, cAttr)
			if cIdx != -1 {
				cIdx += len(cAttr)
				// Determine quote type
				if cIdx < len(tagContentOriginal) {
					quote := tagContentOriginal[cIdx]
					if quote == '"' || quote == '\'' {
						cIdx++ // skip opening quote
						// find closing quote
						closeQuoteIdx := bytes.IndexByte(tagContentOriginal[cIdx:], quote)
						if closeQuoteIdx != -1 {
							description = string(tagContentOriginal[cIdx : cIdx+closeQuoteIdx])
							// Decode HTML entities here if necessary (e.g. html.UnescapeString)
						}
					}
				}
			}
			break // Found it
		}
		cursor += endTag
	}

	return title, description, nil
}

