// httpClient is defined globally.
// We use a custom Dial function (safeDial) to enforce SSRF protection by validating IPs.
var httpClient = &fasthttp.Client{
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     100,
	Dial:                safeDial,
}

// safeDial resolves the hostname and checks if the IP is private/local before dialing.
// This prevents Server-Side Request Forgery (SSRF) vulnerabilities.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs. If any is private, block the request.
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("security: access to private IP %s is forbidden", ip.String())
		}
	}

	// If we are here, all IPs are public.
	// We dial the first one directly to ensure we connect to the validated IP.
	if len(ips) == 0 {
		return nil, fmt.Errorf("no IP addresses found for %s", host)
	}

	targetIP := ips[0]
	// Dial the specific IP to prevent DNS rebinding issues
	return net.DialTimeout("tcp", net.JoinHostPort(targetIP.String(), port), 5*time.Second)
}

// isPrivateIP determines if a net.IP is a private, loopback, or link-local address.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() || ip.IsUnspecified() {
		return true
	}

	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		}
		return false
	}

	// IPv6 Unique Local Addresses (fc00::/7)
	if len(ip) == net.IPv6len && (ip[0]&0xfe == 0xfc) {
		return true
	}

	return false
}

