		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// safeDial establishes a connection only to public IPs to prevent SSRF.
// It resolves the IP first, checks it, and then dials the IP directly to prevent DNS rebinding.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var targetIP net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			continue // Skip private IPs
		}
		targetIP = ip
		break
	}

	if targetIP == nil {
		return nil, errors.New("blocked: resolved to private or invalid IP address")
	}

	// Dial the specific validated IP.
	// JoinHostPort handles IPv6 brackets automatically.
	safeAddr := net.JoinHostPort(targetIP.String(), port)
	return fasthttp.DialDualStack(safeAddr)
}

// isPrivateIP checks if an IP is private, loopback, or link-local.
func isPrivateIP(ip net.IP) bool {
	// Check if loopback or multicast (general unsafe ranges)
	if ip.IsLoopback() || ip.IsMulticast() || ip.IsUnspecified() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check IPv4 Private Ranges (RFC 1918)
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (Link Local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		return false
	}

	// Check IPv6 Unique Local Addresses (fc00::/7)
	// First byte is 1111 110x -> 0xFC or 0xFD
	if len(ip) == 16 {
		if ip[0]&0xfe == 0xfc {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML using Regex.
// Note: For production systems, a proper HTML tokenizer (golang.org/x/net/html) is recommended,
// but regex is used here to avoid external dependencies in this snippet.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Read the content (already limited by MaxResponseBodySize in client)
	content, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	// Find Title
	matches := titleRegex.FindSubmatch(content)
	if len(matches) > 1 {
		title = string(matches[1])
		title = strings.TrimSpace(title)
	}

	// Find Description
	// Try <meta name="description" content="...">
	descMatches := metaDescRegex.FindSubmatch(content)
	if len(descMatches) > 1 {
		description = string(descMatches[1])
	} else {
		// Try <meta content="..." name="description">
		descMatches = metaDescAltRegex.FindSubmatch(content)
		if len(descMatches) > 1 {
			description = string(descMatches[1])
		}
	}

	description = strings.TrimSpace(description)

	return title, description, nil
}

