// parseHTMLPreview extracts title and meta description from HTML using golang.org/x/net/html.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			err := tokenizer.Err()
			if err == io.EOF {
				// End of file, return what we found
				return title, description, nil
			}
			return title, description, err

		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()

			// Extract Title
			if token.Data == "title" {
				// The next token should be the text content of the title
				tokenType = tokenizer.Next()
				if tokenType == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}

			// Extract Meta Description
			if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}

				if strings.EqualFold(name, "description") {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Optimization: If we found both, we can stop parsing
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

