// Regex patterns for extracting metadata.
// (?i) makes it case-insensitive.
// (?s) allows dot (.) to match newlines.
var (
	titleRegex = regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	descRegex  = regexp.MustCompile(`(?is)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
)

// httpClient is a global client instance to reuse connections.
// Requirements implemented:
// 1. Dial set to fasthttp.DialDualStack.
// 2. Timeout set to 3 seconds (via ReadTimeout/WriteTimeout).
var httpClient = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  3 * time.Second,
	WriteTimeout: 3 * time.Second,
}

// PreviewRequest represents the incoming JSON body.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Start the server on port 8080.
	// In a production environment, you might handle graceful shutdown and dynamic ports.
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

// FetchURLPreview handles the POST request to fetch and parse URL metadata.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// 1. Validate Request Method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// 2. Parse JSON Body
	var reqBody PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// 3. Prepare the Request and Response objects
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	// 4. Fetch the URL
	// Requirement: MUST use fasthttp.Client.DoRedirects method.
	// We allow a maximum of 10 redirects.
	err := httpClient.DoRedirects(req, resp, 10)
	if err != nil {
		// This handles timeouts (from Client config) and network errors
		ctx.Error("Failed to fetch URL: "+err.Error(), fasthttp.StatusBadGateway)
		return
	}

	// 5. Parse HTML Content
	// Note: In a full production system, a robust HTML parser (like x/net/html)
	// should be used. Here we use Regex for a self-contained solution.
	body := resp.Body()

	var title, description string

	// Extract Title
	if matches := titleRegex.FindSubmatch(body); len(matches) > 1 {
		title = string(matches[1])
	}

	// Extract Meta Description
	// This regex handles standard <meta name="description" content="..."> format.
	if matches := descRegex.FindSubmatch(body); len(matches) > 1 {
		description = string(matches[1])
	}

	// 6. Return JSON Response
	response := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.Response.Header.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(response); err != nil {
		ctx.Error("Internal Server Error", fasthttp.StatusInternalServerError)
	}
}

