package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"net"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// client is the global fasthttp client instance.
var client *fasthttp.Client
var privateIPBlocks []*net.IPNet

func init() {
	// Initialize private IP blocks for SSRF protection
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPBlocks = append(privateIPBlocks, block)
		}
	}

	// Initialize the client with a custom Dial function for SSRF protection
	// and timeouts to prevent hanging (fixing the timeout error).
	client = &fasthttp.Client{
		Dial:         ssrfSafeDial,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 5 * time.Second,
	}
}

// isPrivateIP checks if an IP address belongs to a private or loopback range.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// ssrfSafeDial is a custom dialer that resolves the hostname, checks for private IPs,
// and dials the resolved IP directly to prevent DNS rebinding.
func ssrfSafeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Check if host is an IP literal
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP %s is forbidden", host)
		}
		return net.DialTimeout("tcp", addr, 5*time.Second)
	}

	// Resolve hostname
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Verify resolved IPs and pick a safe one
	var targetIP net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("resolved to private IP %s", ip.String())
		}
		if targetIP == nil {
			targetIP = ip
		}
	}

	if targetIP == nil {
		return nil, fmt.Errorf("no IP found for %s", host)
	}

	// Dial the specific IP to prevent DNS rebinding
	return net.DialTimeout("tcp", net.JoinHostPort(targetIP.String(), port), 5*time.Second)
}

// PreviewRequest represents the expected JSON input.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON output.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview is the fasthttp handler to process the request.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure the request method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		fmt.Fprintf(ctx, "Method not allowed")
		return
	}

	// Parse JSON body
	var reqData PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "Invalid JSON body"}, fasthttp.StatusBadRequest)
		return
	}

	if reqData.URL == "" {
		sendJSONResponse(ctx, PreviewResponse{Error: "URL field is required"}, fasthttp.StatusBadRequest)
		return
	}

	// Validate Scheme (HTTP/HTTPS only)
	if !strings.HasPrefix(reqData.URL, "http://") && !strings.HasPrefix(reqData.URL, "https://") {
		sendJSONResponse(ctx, PreviewResponse{Error: "Only HTTP and HTTPS schemes are allowed"}, fasthttp.StatusBadRequest)
		return
	}

	// Acquire request and response objects from the pool to minimize allocations
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Prepare the upstream request
	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Set a User-Agent to act like a standard browser/bot
	req.Header.SetUserAgent("URLPreviewFetcher/1.0")

	// Requirement: Use fasthttp.Client.DoRedirects
	// We allow up to 10 redirects.
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}, fasthttp.StatusBadGateway)
		return
	}

	// Check if upstream returned a success status
	if resp.StatusCode() < 200 || resp.StatusCode() >= 300 {
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Upstream returned status: %d", resp.StatusCode())}, fasthttp.StatusBadGateway)
		return
	}

	// Parse the HTML body
	title, desc, err := extractMetadata(resp.Body())
	if err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "Failed to parse HTML content"}, fasthttp.StatusInternalServerError)
		return
	}

	// Return success response
	sendJSONResponse(ctx, PreviewResponse{
		Title:       title,
		Description: desc,
		URL:         reqData.URL,
	}, fasthttp.StatusOK)
}

// extractMetadata parses HTML bytes to find the <title> and <meta name="description">.
func extractMetadata(htmlBody []byte) (title string, description string, err error) {
	doc, err := html.Parse(bytes.NewReader(htmlBody))
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" {
				// usually the title text is the first child of the title tag
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, a := range n.Attr {
					if a.Key == "name" {
						nameAttr = a.Val
					}
					if a.Key == "content" {
						contentAttr = a.Val
					}
				}
				// Case-insensitive check for "description"
				if strings.EqualFold(nameAttr, "description") {
					description = contentAttr
				}
			}
		}

		// Stop traversal if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// sendJSONResponse helper to write JSON to the fasthttp context
func sendJSONResponse(ctx *fasthttp.RequestCtx, data PreviewResponse, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(data); err != nil {
		log.Printf("Error encoding response: %v", err)
	}
}

func main() {
	port := ":8080"
	fmt.Printf("Server starting on %s\n", port)
	if err := fasthttp.ListenAndServe(port, FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

