// Private IP blocks to blacklist for SSRF protection.
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, _ := net.ParseCIDR(cidr)
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP address belongs to a private or reserved network.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial resolves the address and checks for private IPs to prevent SSRF.
// It also mitigates DNS rebinding by dialing the resolved IP directly.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var targetIP net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			targetIP = ip
			break
		}
	}

	if targetIP == nil {
		return nil, errors.New("security: blocked access to private or restricted IP")
	}

	// Dial the specific IP address combined with the port.
	// This prevents Time-of-Check Time-of-Use (TOCTOU) / DNS Rebinding attacks.
	tcpAddr := net.JoinHostPort(targetIP.String(), port)
	return net.DialTimeout("tcp", tcpAddr, 5*time.Second)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and structure
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Strict scheme check
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prevent credentials in URL (potential leak or confusion)
	if parsedURL.User != nil {
		ctx.Error("URLs with credentials are not allowed", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with security constraints
	client := &fasthttp.Client{
		Dial:                safeDial, // Inject custom dialer for SSRF protection
		ReadTimeout:         5 * time.Second,
		WriteTimeout:        5 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		// DoS Protection: Limit response body size (e.g., 2MB) to prevent OOM
		MaxResponseBodySize: 2 * 1024 * 1024,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Limit redirects to prevent infinite loops
	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		// Differentiate between generic errors and body size errors
		if err == fasthttp.ErrBodyTooLarge {
			ctx.Error("Target page is too large", fasthttp.StatusBadGateway)
		} else {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		}
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Extract content type to ensure we are parsing HTML
	contentType := string(res.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL did not return HTML content", fasthttp.StatusBadRequest)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description := parseHTMLPreview(bodyBytes)

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML bytes.
// Note: Using regex for HTML is generally discouraged for complex parsing,
// but for a simple preview extractor without external dependencies, it suffices.
func parseHTMLPreview(content []byte) (title, description string) {
	// Convert to string for regex operations (allocates, but body is capped by MaxResponseBodySize)
	html := string(content)

	// Regex for Title
	// Looks for <title>...</title>, case insensitive, non-greedy
	titleRegex := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	if matches := titleRegex.FindStringSubmatch(html); len(matches) > 1 {
		title = strings.TrimSpace(matches[1])
	}

	// Regex for Meta Description
	// Looks for <meta name="description" content="..."> or <meta content="..." name="description">
	// This is a simplified regex and might not catch all variations (e.g. single quotes).
	descRegex := regexp.MustCompile(`(?i)<meta\s+(?:name=["']description["']\s+content=["']([^"']*)["']|content=["']([^"']*)["']\s+name=["']description["'])`)
	if matches := descRegex.FindStringSubmatch(html); len(matches) > 0 {
		if matches[1] != "" {
			description = strings.TrimSpace(matches[1])
		} else if len(matches) > 2 && matches[2] != "" {
			description = strings.TrimSpace(matches[2])
		}
	}

	return title, description
}

