// extractMetadata parses HTML bytes to find the Title and Meta Description.
func extractMetadata(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)

