		// Timeouts to prevent Slowloris/resource exhaustion
		ReadTimeout:         5 * time.Second,
		WriteTimeout:        5 * time.Second,
		MaxConnWaitTimeout:  5 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,

		// Limit response size to prevent DoS (e.g., 2MB limit)
		MaxResponseBodySize: 2 * 1024 * 1024, 

		// Connection limits
		MaxConnsPerHost: 10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Limit redirects to prevent loops
	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		// Differentiate between security block and network error
		if strings.Contains(err.Error(), "security: blocked") {
			ctx.Error("Access to target resource is forbidden", fasthttp.StatusForbidden)
		} else if err == fasthttp.ErrBodyTooLarge {
			ctx.Error("Target page is too large", fasthttp.StatusUnprocessableEntity)
		} else {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		}
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate Content-Type to avoid parsing binary files
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
		ctx.Error("Target is not an HTML page", fasthttp.StatusBadRequest)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

