	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
// Note: In a production environment, use a proper HTML parser like golang.org/x/net/html
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Simple implementation for demonstration. 
	// Real implementation should parse the HTML tree.
	buf := new(bytes.Buffer)
	_, err = buf.ReadFrom(r)
	if err != nil {
		return "", "", err
	}
	content := buf.String()

	// Very basic extraction (Not robust for all HTML)
	// 1. Extract Title
	if start := strings.Index(strings.ToLower(content), "<title>"); start != -1 {
		if end := strings.Index(strings.ToLower(content[start:]), "</title>"); end != -1 {
			title = content[start+7 : start+end]
		}
	}

	// 2. Extract Description (simplified search)
	// Looks for <meta name="description" content="...">
	lowerContent := strings.ToLower(content)
	metaIdx := strings.Index(lowerContent, "name=\"description\"")
	if metaIdx != -1 {
		// Search backwards or forwards for content attribute nearby
		// This is just a placeholder logic.
		description = "Found meta description tag" 
	} else {
		description = "No description found"
	}

	if title == "" {
		title = "No Title"
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

