)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// httpClient is a shared client to utilize connection pooling effectively.
var httpClient *fasthttp.Client

// privateIPBlocks contains the list of private IP ranges to block for SSRF protection.
var privateIPBlocks []*net.IPNet

func init() {
	// Initialize private IP blocks (RFC1918, Loopback, Link-Local, etc.)
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err != nil {
			panic(fmt.Errorf("parse error on %q: %v", cidr, err))
		}
		privateIPBlocks = append(privateIPBlocks, block)
	}

	httpClient = &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     100,
		// Use a custom Dial function to enforce SSRF protection
		Dial: safeDial,
	}
}

// isPrivateIP checks if an IP address is in a private/reserved range.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial resolves the hostname and checks if the resulting IP is private.
// It connects directly to the resolved IP to prevent DNS rebinding attacks.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve the host to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Find a valid public IP
	var targetIP net.IP
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			targetIP = ip
			break
		}
	}

	if targetIP == nil {
		return nil, errors.New("access to private IP addresses is denied")
	}

	// Connect specifically to the validated IP address
	addrWithIP := net.JoinHostPort(targetIP.String(), port)
	dialer := &net.Dialer{Timeout: 5 * time.Second}
	return dialer.Dial("tcp", addrWithIP)
}

func main() {
	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Use the shared client to fetch with redirect support
	maxRedirectCounts := 10
	if err := httpClient.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML using a tokenizer.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				return title, description, nil
			}
			return title, description, tokenizer.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := tokenizer.Token()

			// Check for <title>
			if t.Data == "title" {
				if tokenizer.Next() == html.TextToken {
					title = html.UnescapeString(tokenizer.Token().Data)
				}
			} else if t.Data == "meta" {
				// Check for <meta name="description" content="...">
				var name, content string
				for _, attr := range t.Attr {
					k := strings.ToLower(attr.Key)
					if k == "name" {
						name = strings.ToLower(attr.Val)
					} else if k == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = html.UnescapeString(content)
				}
			}
		}

		// Optimization: If both are found, we can stop parsing
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

