// isPrivateIP checks if an IP address belongs to a private or local network.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial is a custom dialer that resolves IPs and checks against a blocklist to prevent SSRF.
