	if targetIP == nil {
		return nil, errors.New("security: blocked access to private/local IP address")
	}

	// Dial the specific validated IP using TCP
	// We join the IP and port manually to ensure we connect to the validated address
	tcpAddr := net.JoinHostPort(targetIP.String(), port)
	return fasthttp.Dial(tcpAddr)
