// Private IP blocks for SSRF protection
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPBlocks = append(privateIPBlocks, block)
		}
	}
}

// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// ssrfSafeDial is a custom dialer that resolves IPs and blocks private addresses
func ssrfSafeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		// If splitting fails, assume addr is just host (though fasthttp usually sends host:port)
		host = addr
		port = "80"
	}

	// Resolve the host to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs for private ranges
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private IP %s is denied", ip.String())
		}
	}

	if len(ips) == 0 {
		return nil, fmt.Errorf("no IP addresses found for host: %s", host)
	}

	// Dial the first resolved IP directly to prevent DNS rebinding
	// JoinHostPort handles IPv6 brackets automatically
	targetAddr := net.JoinHostPort(ips[0].String(), port)
	return net.DialTimeout("tcp", targetAddr, 5*time.Second)
}

// Global client to ensure connection reuse and pooling.
// Configured with ssrfSafeDial to prevent SSRF attacks.
var httpClient = &fasthttp.Client{
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     100,
	Dial:                ssrfSafeDial,
}

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

