	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Use global client to fetch with redirects
	maxRedirectCounts := 10
	if err := httpClient.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML content
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// sendJSONError helper to return errors in JSON format
func sendJSONError(ctx *fasthttp.RequestCtx, msg string, statusCode int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(statusCode)
	resp := PreviewResponse{Error: msg}
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using x/net/html tokenizer.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	for {
		tt := z.Next()

		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return title, description, z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			name, hasAttr := z.TagName()

			// Check for <title>
			if bytes.Equal(name, []byte("title")) {
				if z.Next() == html.TextToken {
					title = string(z.Text())
				}
			} else if bytes.Equal(name, []byte("meta")) {
				// Check for <meta name="description" content="...">
				var nameAttr, contentAttr string
				for hasAttr {
					var key, val []byte
					key, val, hasAttr = z.TagAttr()
					if bytes.Equal(key, []byte("name")) {
						nameAttr = string(val)
					} else if bytes.Equal(key, []byte("content")) {
						contentAttr = string(val)
					}
				}
				if strings.EqualFold(nameAttr, "description") {
					description = contentAttr
				}
			}
		}

		// Optimization: Return early if both found
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

