// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// privateIPBlocks contains IP ranges that are not allowed to be accessed (SSRF protection).
var privateIPBlocks []*net.IPNet

func init() {
	for _, cidr := range []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local (Cloud metadata)
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local
	} {
		_, block, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPBlocks = append(privateIPBlocks, block)
		}
	}
}

// isPrivateIP checks if an IP address belongs to a private or restricted network.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalMulticast() || ip.IsLinkLocalUnicast() {
		return true
	}

	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// secureDialer resolves the address, checks for SSRF, and dials the specific IP.
func secureDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var targetIP net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			continue
		}
		targetIP = ip
		break
	}

	if targetIP == nil {
		return nil, errors.New("access to target IP is denied (SSRF protection)")
	}

	// Dial the specific validated IP to prevent DNS rebinding
	// We assume TCP for HTTP/HTTPS
	tcpAddr := &net.TCPAddr{
		IP:   targetIP,
		Port: 0, // Port parsing is handled by SplitHostPort, but we need int
	}
	// Re-parse port to int
	if p, err := net.LookupPort("tcp", port); err == nil {
		tcpAddr.Port = p
	} else {
		return nil, err
	}

	return net.DialTCP("tcp", nil, tcpAddr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme and structure
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Configure fasthttp Client with security constraints
	client := &fasthttp.Client{
		Dial:                secureDialer,      // Use custom dialer for SSRF protection
		ReadTimeout:         5 * time.Second,   // Reduced timeout
		WriteTimeout:        5 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     5,                 // Limit concurrency per host
		MaxResponseBodySize: 2 * 1024 * 1024,   // Limit response body to 2MB (DoS protection)
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Limit redirects to prevent infinite loops or slowloris-style delays
	maxRedirectCounts := 3
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		// Differentiate between security blocks and network errors if needed
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate Content-Type to ensure we are parsing HTML
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("Target URL is not an HTML page", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
// Note: In a production environment, use "golang.org/x/net/html".
// This is a simplified byte-scanner to avoid external dependencies for this exercise.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Read the content (limit handled by MaxResponseBodySize in client)
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	// Helper to find tag content case-insensitively
	findTagContent := func(data []byte, tagName string) string {
		lowerData := bytes.ToLower(data)
		startTag := []byte("<" + tagName + ">")
		endTag := []byte("</" + tagName + ">")

		start := bytes.Index(lowerData, startTag)
		if start == -1 {
			// Try with attributes
			startTagPrefix := []byte("<" + tagName + " ")
			start = bytes.Index(lowerData, startTagPrefix)
			if start == -1 {
				return ""
			}
			// Find closing bracket of the opening tag
			closeBracket := bytes.Index(lowerData[start:], []byte(">"))
			if closeBracket == -1 {
				return ""
			}
			start += closeBracket + 1
		} else {
			start += len(startTag)
		}

		end := bytes.Index(lowerData[start:], endTag)
		if end == -1 {
			return ""
		}

		return string(data[start : start+end])
	}

	// Helper to find meta description
	findMetaDescription := func(data []byte) string {
		lowerData := bytes.ToLower(data)
		metaStart := []byte("<meta")

		pos := 0
		for {
			idx := bytes.Index(lowerData[pos:], metaStart)
			if idx == -1 {
				break
			}
			pos += idx

			// Find the end of this tag
			endTag := bytes.Index(lowerData[pos:], []byte(">"))
			if endTag == -1 {
				break
			}

			tagContent := lowerData[pos : pos+endTag]
			// Check if it's name="description"
			if bytes.Contains(tagContent, []byte(`name="description"`)) || 
			   bytes.Contains(tagContent, []byte(`name='description'`)) {

				// Extract content attribute
				contentPrefix := []byte("content=")
				cIdx := bytes.Index(tagContent, contentPrefix)
				if cIdx != -1 {
					// This is a very rough parser. Real HTML parsing is complex.
					// We grab the raw string from the original data to preserve case
					rawTag := data[pos : pos+endTag]

					// Re-find content in raw tag
					rawLower := bytes.ToLower(rawTag)
					cIdx = bytes.Index(rawLower, contentPrefix)

					quoteChar := rawTag[cIdx+len(contentPrefix)]
					if quoteChar == '"' || quoteChar == '\'' {
						valStart := cIdx + len(contentPrefix) + 1
						valEnd := bytes.IndexByte(rawTag[valStart:], quoteChar)
						if valEnd != -1 {
							return string(rawTag[valStart : valStart+valEnd])
						}
					}
				}
			}
			pos += endTag + 1
		}
		return ""
	}

	title = findTagContent(data, "title")
	description = findMetaDescription(data)

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

