// FetchURLPreview handles the POST request to fetch and parse URL metadata.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Ensure the method is POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var payload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if payload.URL == "" {
		sendJSONError(ctx, "URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Prepare the external request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Set the URL and Method (GET to fetch content)
	req.SetRequestURI(payload.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Mimic a browser to avoid some bot protections
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; PreviewFetcher/1.0)")

	// REQUIREMENT: Use fasthttp.Client.DoRedirects method
	// We allow up to 5 redirects.
	err := httpClient.DoRedirects(req, resp, 5)
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Remote server returned status: %d", resp.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

