	title, desc, err := parseHTML(resp.Body())
	if err != nil {
		sendJSONError(ctx, "Failed to parse HTML content", fasthttp.StatusInternalServerError)
		return
	}

	// Send success response
	response := ResponsePayload{
		Title:       title,
		Description: desc,
	}
	sendJSONResponse(ctx, response, fasthttp.StatusOK)
}

// parseHTML parses the HTML body bytes to extract title and meta description.
func parseHTML(body []byte) (string, string, error) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", "", err
	}

	var title, description string
	var f func(*html.Node)

	f = func(n *html.Node) {
		// Stop traversing if we found both (optimization)
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Extract Meta Description
			if n.Data == "meta" && description == "" {
				var name, content string
				for _, a := range n.Attr {
					if a.Key == "name" {
						name = a.Val
					}
					if a.Key == "content" {
						content = a.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description, nil
}

// sendJSONResponse sends a successful JSON response.
func sendJSONResponse(ctx *fasthttp.RequestCtx, payload interface{}, statusCode int) {
	ctx.Response.Header.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	if err := json.NewEncoder(ctx).Encode(payload); err != nil {
		ctx.Error("Internal Server Error", fasthttp.StatusInternalServerError)
	}
}

// sendJSONError sends an error response in JSON format.
func sendJSONError(ctx *fasthttp.RequestCtx, msg string, statusCode int) {
	ctx.Response.Header.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	json.NewEncoder(ctx).Encode(ResponsePayload{Error: msg})
}

func main() {
	port := ":8080"
	fmt.Printf("Server starting on %s...\n", port)

	// Start the server with the handler
	if err := fasthttp.ListenAndServe(port, FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

